from dataclasses import dataclass, field
from typing import Any, Callable
from collections import defaultdict

@dataclass
class SharedBlackboard:
    """Shared state blackboard with conflict resolution and subscriptions."""
    _store: dict[str, dict] = field(default_factory=dict)
    _history: list[dict] = field(default_factory=list)
    _subscribers: dict[str, list[Callable]] = field(default_factory=lambda: defaultdict(list))
    _merge_strategies: dict[str, str] = field(default_factory=dict)
    _version: int = 0

    def set_merge_strategy(self, key: str, strategy: str):
        """Set merge strategy for a key: 'lww', 'union', or 'max'."""
        if strategy not in ('lww', 'union', 'max'):
            raise ValueError(f"Unknown strategy: {strategy}")
        self._merge_strategies[key] = strategy

    def _resolve_conflict(self, key: str, old_value: Any, new_value: Any) -> Any:
        """Resolve a write conflict using the configured merge strategy."""
        strategy = self._merge_strategies.get(key, 'lww')

        if strategy == 'lww':
            return new_value
        elif strategy == 'union':
            if isinstance(old_value, list) and isinstance(new_value, list):
                return list(set(old_value + new_value))
            return new_value
        elif strategy == 'max':
            if isinstance(old_value, (int, float)) and isinstance(new_value, (int, float)):
                return max(old_value, new_value)
            return new_value
        return new_value

    def write(self, key: str, value: Any, author: str) -> dict:
        """Write a value to the blackboard with conflict resolution."""
        self._version += 1

        if key in self._store:
            old_value = self._store[key]["value"]
            value = self._resolve_conflict(key, old_value, value)

        entry = {
            "key": key,
            "value": value,
            "author": author,
            "version": self._version
        }
        self._store[key] = entry
        self._history.append(entry)

        # Notify subscribers
        for callback in self._subscribers.get(key, []):
            callback(key, value, author)

        return entry

    def read(self, key: str) -> Any:
        """Read the current value for a key. Returns None if not found."""
        entry = self._store.get(key)
        return entry["value"] if entry else None

    def read_all(self) -> dict[str, Any]:
        """Read all current key-value pairs."""
        return {k: v["value"] for k, v in self._store.items()}

    def subscribe(self, key: str, callback: Callable):
        """Subscribe to changes on a key. Callback receives (key, value, author)."""
        self._subscribers[key].append(callback)

    def get_history(self, key: str = None) -> list[dict]:
        """Get write history, optionally filtered by key."""
        if key is not None:
            return [e for e in self._history if e["key"] == key]
        return list(self._history)

    def get_contributors(self) -> dict[str, int]:
        """Get write count per author."""
        counts = defaultdict(int)
        for entry in self._history:
            counts[entry["author"]] += 1
        return dict(counts)


# Test your implementation
board = SharedBlackboard()
board.set_merge_strategy("findings", "union")
board.set_merge_strategy("score", "max")

board.write("findings", ["SQL injection", "XSS"], "agent-a")
board.write("findings", ["XSS", "CSRF"], "agent-b")
print(f"Merged findings: {board.read('findings')}")

board.write("score", 7.5, "agent-a")
board.write("score", 8.2, "agent-b")
print(f"Max score: {board.read('score')}")

print(f"Contributors: {board.get_contributors()}")
print(f"History entries: {len(board.get_history())}")

from dataclasses import dataclass, field
from collections import defaultdict

@dataclass
class TraceAnalyzer:
    """Analyzes execution traces from multi-agent systems."""
    spans: list[dict] = field(default_factory=list)

    def add_span(self, span: dict):
        """Add a span to the analyzer."""
        self.spans.append(span)

    def get_trace_ids(self) -> list[str]:
        """Get all unique trace IDs."""
        return list(set(s["trace_id"] for s in self.spans))

    def _get_trace_spans(self, trace_id: str) -> list[dict]:
        """Get all spans for a given trace."""
        return [s for s in self.spans if s["trace_id"] == trace_id]

    def get_trace_duration(self, trace_id: str) -> float:
        """Total duration of a trace (max end - min start)."""
        trace_spans = self._get_trace_spans(trace_id)
        if not trace_spans:
            return 0.0
        min_start = min(s["start_ms"] for s in trace_spans)
        max_end = max(s["end_ms"] for s in trace_spans)
        return max_end - min_start

    def find_bottlenecks(self, trace_id: str, top_n: int = 3) -> list[dict]:
        """Find the top_n longest spans in a trace."""
        trace_spans = self._get_trace_spans(trace_id)
        with_duration = []
        for s in trace_spans:
            duration = s["end_ms"] - s["start_ms"]
            with_duration.append({
                "span_id": s["span_id"],
                "agent": s["agent"],
                "operation": s["operation"],
                "duration_ms": duration
            })
        with_duration.sort(key=lambda x: x["duration_ms"], reverse=True)
        return with_duration[:top_n]

    def find_failures(self, trace_id: str) -> list[dict]:
        """Find all failed spans in a trace."""
        trace_spans = self._get_trace_spans(trace_id)
        return [
            {"span_id": s["span_id"], "agent": s["agent"], "operation": s["operation"]}
            for s in trace_spans if s["status"] == "error"
        ]

    def get_agent_stats(self, trace_id: str) -> dict:
        """Per-agent performance statistics."""
        trace_spans = self._get_trace_spans(trace_id)
        stats = defaultdict(lambda: {"total_ms": 0, "span_count": 0, "failure_count": 0})

        for s in trace_spans:
            duration = s["end_ms"] - s["start_ms"]
            agent = s["agent"]
            stats[agent]["total_ms"] += duration
            stats[agent]["span_count"] += 1
            if s["status"] == "error":
                stats[agent]["failure_count"] += 1

        result = {}
        for agent, data in stats.items():
            data["avg_ms"] = round(data["total_ms"] / data["span_count"], 1) if data["span_count"] > 0 else 0
            result[agent] = dict(data)

        return result

    def get_critical_path(self, trace_id: str) -> list[str]:
        """Find the critical path (longest sequential chain from root to leaf)."""
        trace_spans = self._get_trace_spans(trace_id)
        if not trace_spans:
            return []

        # Build parent -> children map
        span_map = {s["span_id"]: s for s in trace_spans}
        children_map = defaultdict(list)
        roots = []

        for s in trace_spans:
            if s["parent_id"] is None:
                roots.append(s)
            else:
                children_map[s["parent_id"]].append(s)

        def find_path(span_id: str) -> list[str]:
            """Recursively find the critical path from this span."""
            kids = children_map.get(span_id, [])
            if not kids:
                return [span_id]

            # Follow the child with the latest end_ms
            latest_child = max(kids, key=lambda c: c["end_ms"])
            return [span_id] + find_path(latest_child["span_id"])

        if not roots:
            return []

        # Start from the root with the latest end time
        root = max(roots, key=lambda r: r["end_ms"])
        return find_path(root["span_id"])


# Test data: a coordinator with 3 parallel workers
analyzer = TraceAnalyzer()
spans = [
    {"span_id": "s1", "parent_id": None, "trace_id": "t1", "agent": "coordinator", "operation": "orchestrate", "start_ms": 0, "end_ms": 5200, "status": "ok"},
    {"span_id": "s2", "parent_id": "s1", "trace_id": "t1", "agent": "security", "operation": "scan", "start_ms": 100, "end_ms": 3500, "status": "ok"},
    {"span_id": "s3", "parent_id": "s1", "trace_id": "t1", "agent": "quality", "operation": "review", "start_ms": 100, "end_ms": 2100, "status": "ok"},
    {"span_id": "s4", "parent_id": "s1", "trace_id": "t1", "agent": "testing", "operation": "coverage", "start_ms": 100, "end_ms": 4600, "status": "error"},
    {"span_id": "s5", "parent_id": "s1", "trace_id": "t1", "agent": "testing", "operation": "coverage_retry", "start_ms": 4700, "end_ms": 5100, "status": "ok"},
    {"span_id": "s6", "parent_id": "s1", "trace_id": "t1", "agent": "coordinator", "operation": "synthesize", "start_ms": 5100, "end_ms": 5200, "status": "ok"},
]

for s in spans:
    analyzer.add_span(s)

print(f"Trace duration: {analyzer.get_trace_duration('t1')}ms")
print(f"Bottlenecks: {analyzer.find_bottlenecks('t1', top_n=3)}")
print(f"Failures: {analyzer.find_failures('t1')}")
print(f"Agent stats: {analyzer.get_agent_stats('t1')}")
print(f"Critical path: {analyzer.get_critical_path('t1')}")
